  *{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Tahoma,Arial,sans-serif;background:#fff;color:#1a1a1a;max-width:360px;margin:0 auto;padding:28px 24px 24px;font-size:13px}
